def shortestPalindrome(s: str) -> str:
    temp = s + '#' + s[::-1]
    table = _get_kmp_table(temp)
    longest_palindrome_prefix_len = table[-1]
    return s[longest_palindrome_prefix_len:][::-1] + s

def _get_kmp_table(s: str) -> list[int]:
    table = [0] * len(s)
    j = 0
    for i in range(1, len(s)):
        while j > 0 and s[i] != s[j]:
            j = table[j - 1]
        if s[i] == s[j]:
            j += 1
        table[i] = j
    return table
